#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>
#include <math.h>
#include <string.h>


#include "vex.h"

using namespace vex;

// Brain should be defined by default
brain Brain;


// START IQ MACROS
#define waitUntil(condition)                                                   \
  do {                                                                         \
    wait(5, msec);                                                             \
  } while (!(condition))

#define repeat(iterations)                                                     \
  for (int iterator = 0; iterator < iterations; iterator++)
// END IQ MACROS


// Robot configuration code.
motor LeftDriveSmart = motor(PORT1, 1, false);
motor RightDriveSmart = motor(PORT6, 1, true);
gyro DrivetrainGyro = gyro(PORT4, true);
smartdrive Drivetrain = smartdrive(LeftDriveSmart, RightDriveSmart, DrivetrainGyro, 200);


void calibrateDrivetrain() {
  wait(200, msec);
  Brain.Screen.print("Calibrating");
  Brain.Screen.newLine();
  Brain.Screen.print("Gyro");
  DrivetrainGyro.calibrate();
  while (DrivetrainGyro.isCalibrating()) {
    wait(25, msec);
  }

  // Clears the screen and returns the cursor to row 1, column 1.
  Brain.Screen.clearScreen();
  Brain.Screen.setCursor(1, 1);
}

// Generated code.

// Include the IQ Library
#include "vex.h"

// Allows for easier use of the VEX Library
using namespace vex;

float myVariable;

// "when started" hat block
int whenStarted1() {
  // Driving Forward and Turning Right
  Drivetrain.driveFor(forward, 200.0, mm, true);
  Drivetrain.turnFor(right, 90.0, degrees, true);
  // Driving Forward and Turning Left
  Drivetrain.driveFor(forward, 200.0, mm, true);
  Drivetrain.turnFor(left, 90.0, degrees, true);
  // Driving Reverse and Turning Left
  Drivetrain.driveFor(reverse, 200.0, mm, true);
  Drivetrain.turnFor(left, 90.0, degrees, true);
  // Driving Forward and Turning Right
  Drivetrain.driveFor(forward, 200.0, mm, true);
  Drivetrain.turnFor(right, 90.0, degrees, true);
  return 0;
}


int main() {
  // Calibrate the Drivetrain Gyro
  calibrateDrivetrain();

  whenStarted1();
}

