//----------------------------------------------------------------------------
//                                                                            
//    Project:          Turning Accurately                                         
//    Description:      This example will show how to use different drivetrain 
//                      turning commands to control the robot
//    Brain Supported:  1st generation
//    Configuration:    Standard Drive Base (Drivetrain 2-motor, Gyro)
//                      Gyro in Port 4                   
//                                                                            
//---------------------------------------------------------------------------- 

// Include the IQ Library
#include "vex.h"

// Allows for easier use of the VEX Library
using namespace vex;

int main() {
  // Initializing Robot Configuration. DO NOT REMOVE!
  vexcodeInit();
  // Begin project code
  // The robot is able to turn continuously until told to stop or do something else
  Drivetrain.turn(left);
  wait(4, seconds);
  Drivetrain.stop();

  // A brief delay to observe the result of the turning action
  wait(1, seconds);
  Drivetrain.turnFor(right, 180, degrees);

  // A brief delay to observe the result of the turning action
  wait(1, seconds);

  // A Drivetrain can be used to turn to an exact heading when using a Gyro
  // based on the sensor's feedback
  // This command will point the robot back to a rotation value of 0 (its starting orientation)
  // and will determine the fastest direction to turn
  while (Drivetrain.rotation(degrees) > 0) {
    Brain.Screen.print("Rotation: %.02f", Drivetrain.rotation(degrees));
    Drivetrain.turnToRotation(0, degrees);

    wait(0.4, seconds);

    // Clear screen and reset cursor to top left of the screen
    Brain.Screen.clearScreen();
    Brain.Screen.setCursor(1, 1);
  }
  return 0;
}

