//    Project:          Using Color sensor                                         
//    Description:      This example will print out the name, hue, and brightness of 
//                      the color that the robot detects to the Brain screen. 
//                      If the robot detects color blue, it will drive forward.
//    Brain Supported:  1st generation
//    Configuration:    Standard Drive Base (Drivetrain 2-motor, Gyro)
//                      Gyro in Port 4                   
//                      Color Sensor in Port 3                
//                                                                            
//---------------------------------------------------------------------------------- 

// Include the IQ Library
#include "vex.h"

// Allows for easier use of the VEX Library
using namespace vex;

int main() {
  // Initializing Robot Configuration. DO NOT REMOVE!
  vexcodeInit();
    // Begin project code
  // Turn the Color Sensor Lamp on
  Color3.setLight(100, percent);

  while (true) {
    // If the robot detects color blue, it will drive forward
    if (Color3.detects(blue)) {
      Drivetrain.drive(forward);
    } else {
      Drivetrain.stop();
    }

    // Erase the Brain screen at the beginning of the project and set
    // the printing location (cursor) to the top left corner
    Brain.Screen.clearScreen();
    Brain.Screen.setCursor(1, 1);

    // Compare the name of the color to see what to print 
    if (Color3.colorname() == red) {
      Brain.Screen.print("Color: Red");
      Brain.Screen.newLine();
    } else if (Color3.colorname() == blue) {
      Brain.Screen.print("Color: Blue");
      Brain.Screen.newLine();
    } else if (Color3.colorname() == green) {
      Brain.Screen.print("Color: Green");
      Brain.Screen.newLine();
    } else {
      Brain.Screen.print("Color: Unknown");
      Brain.Screen.newLine();
    }

    // Print the hue of the detected color
    Brain.Screen.print("Hue: %d", Color3.hue());
    Brain.Screen.newLine();

    // Print the brightness of the detected color
    Brain.Screen.print("Brightness: %d", Color3.brightness());
    Brain.Screen.newLine();

    // A brief delay to allow text to be printed without distortion or tearing
    wait(0.05, seconds);
  }
  return 0;
}

