  // Initializing Robot Configuration. DO NOT REMOVE!
  vexcodeInit();
  // Begin project code
  // The robot starts off driving forward
  Drivetrain.drive(forward);
  TouchLED2.setColor(green);

  // The robot will stop driving when the Touch LED has been pressed
  waitUntil(TouchLED2.pressing());
  TouchLED2.setColor(red);
  Drivetrain.stop();

  // The Touch LED will wait 1 second before changing the brightness to 10%
  wait(1, seconds);
  TouchLED2.setBrightness(10);

  // The Touch LED will wait 1 second before fading the color slowly from red to yellow
  wait(1, seconds);
  TouchLED2.setFade(slow);
  TouchLED2.setColor(yellow);

  return 0;
}

