//----------------------------------------------------------------------------
//                                                                            
//    Project:          Playing Notes                                                                                                                                                
//    Description:      This program will play different notes depending on
//                      which button is pressed on the Brain.
//                      A list of supported note values can be found in the help
//                      for the Brain.playNote() command.
//    Brain Supported:  1st generation
//    Configuration:    None                                   
//                                                                            
//----------------------------------------------------------------------------

// Include the IQ Library
#include "vex.h"

// Allows for easier use of the VEX Library
using namespace vex;

int main() {
  // Initializing Robot Configuration. DO NOT REMOVE!
  vexcodeInit();
  // Begin project code

  // Loop to keep detecting button presses
  while (true) {
    if (Brain.buttonUp.pressing()) {
      // Plays a C whole note
      Brain.playNote(3, 0, 1000);

      // Half-second wait so each note is only played once
      wait(0.5, seconds);
    }
    if (Brain.buttonDown.pressing()) {
      // Plays an E half note
      Brain.playNote(3, 2, 500);

      // Half-second wait so each note is only played once
      wait(0.5, seconds);
    }
    if (Brain.buttonCheck.pressing()) {
      // Plays an A quarter note
      Brain.playNote(3, 5, 250);

      // Half-second wait so each note is only played once
      wait(0.5, seconds);
    }

    wait(20, msec);
  }  
}

