    }
    if (Brain.buttonRight.pressing()) {
      Brain.playSound(headlightsOn);

      // Half-second wait so each sound is only played once
      wait(0.5, seconds);
    }
    if (Brain.buttonCheck.pressing()) {
      Brain.playSound(wrongWay);

      // Half-second wait so each sound is only played once
      wait(0.5, seconds);
    }

    wait(20, msec);
  }  
