// Include the IQ Library
#include "vex.h"

// Allows for easier use of the VEX Library
using namespace vex;

int main() {
  // Initializing Robot Configuration. DO NOT REMOVE!
  vexcodeInit();
  // Begin project code
  // Drive the robot forward towards an object
  Drivetrain.driveFor(forward, 200, mm);

  // Spin the arm forward while the arm angle is less than 90 degrees
  while (ArmMotor.position(degrees) < 90) {
    ArmMotor.spin(forward);
    // A brief delay inside of a loop to allow other resources to run
    wait(0.05, seconds);
  }

  // Spin the arm reverse while the arm angle is greater than 10 degrees
  while (ArmMotor.position(degrees) > 10) {
    ArmMotor.spin(reverse);
    // A brief delay inside of a loop to allow other resources to run
    wait(0.05, seconds);
  }

  // Once the arm reaches an angle of less than 10 degrees
  // Stop the arm motor
  ArmMotor.stop();
}

