// ----------------------------------------------------------------------
//
//    Project:          Complex Decisions (and, or, not)
//    Description:      This example will use logical operators to create
//                      complex decisions based on multiple sensor inputs
//    Brain Supported:  1st generation
//    Configuration:    Bumper in Port 8
//                      TouchLED in Port 2
//
// ----------------------------------------------------------------------

// Include the IQ Library
#include "vex.h"

// Allows for easier use of the VEX Library
using namespace vex;

int main() {
  // Initializing Robot Configuration. DO NOT REMOVE!
  vexcodeInit();
  // Begin project code
  // Place your conditionals in a while (true) loop 
  // to keep the sensors checking for new events.
  while (true) {

    // Clear the Brain's screen and place the cursor at row one, column one.
    Brain.Screen.clearScreen();
    Brain.Screen.setCursor(1, 1);

    // The '&&' (and) operator requires BOTH conditions to be "true"
    // for the conditional statement to evaluate as "true".
    // In this case, if the Bumper is pressed AND the Touch LED touched.
    if (TouchLED2.pressing() && Bumper8.pressing()) {
      Brain.Screen.print("AND Statement: true");
    } 
    else {
      Brain.Screen.print("AND Statement: false");
    }

    // Move the cursor to the next line.
    Brain.Screen.newLine();

    // The '||' (or) operator requires EITHER condition to be "true"
    // for the conditional statement to evaluate as "true".
    // In this case, if the Bumper is pressed OR the Touch LED touched.
    if (TouchLED2.pressing() || Bumper8.pressing()) {
      Brain.Screen.print("OR Statement: true");
    } 
    else {
      Brain.Screen.print("OR Statement: false");
    }

    // Move the cursor to the next line
    Brain.Screen.newLine();

    // The '!' (not) operator checks the inverse (opposite) of the condition's value.
    // In this case, if the Bumper is NOT pressed.
    if (!Bumper8.pressing()) {
      Brain.Screen.print("NOT Statement: true");
    } 
    else {
      Brain.Screen.print("NOT Statement: false");
    }

    // Brief wait needed for optimal performance.
    wait(20, msec);
  }
}

