// ----------------------------------------------------------------------------
//                                                                            
//    Project:          Creating Classes                                        
//    Description:      This example will show how to create classes in VEXcode
//    Brain Supported:  1st generation                        
//    Configuration:    None            
//                                                                            
// ---------------------------------------------------------------------------- 

// Include the IQ Library
#include "vex.h"

// Allows for easier use of the VEX Library
using namespace vex;

// Create a class by using the "class" keyword with two curly brackets and a semicolon (;)
// The code for the class will go between the curly brackets.
class TrackValues {

  // Variables can be made in the class and can be used
  // by functions in the class.
  int value;

  // The "public" keyword allows the functions in the class to be used
  // by instances of the class.
  public:
    // When creating an instance of the class, the constructor function will run automatically.
    TrackValues(int value) {
      Brain.Screen.clearScreen();
      Brain.Screen.setCursor(1, 1);

      // The "this" keyword refers to the current instance of the class
      //  and gives access to the class' variables
      this->value = value; 
    }

    // Class functions can use standard robot commands
    void printValue() {
      Brain.Screen.print("Current Value: %d", this->value);
      Brain.Screen.setCursor(1, 1);
    }

    // Class functions can accept parameters
    void resetValue(int newValue) {
      this->value = newValue;
    }

    // Class functions can return values
    int getValue() {
      return this->value;
    }

    // Class functions can modify variables
    void addOne() {
      this->value += 1;
    }

    void subtractOne() {
      this->value -= 1;
    }
};

int main() {
  // Initializing Robot Configuration. DO NOT REMOVE!
  vexcodeInit();
  // Begin project code
  // An instance (a copy) of a class can be created by using the constructor
  // and passing the required parameters.
  TrackValues instance1 = TrackValues(36);

  // Functions within the class can be called with this format:
  // ClassInstance.function(parameters);
  instance1.printValue();

  // Wait so the values can be seen.
  wait(3, seconds);

  // Class instance functions can be used multiple times.
  instance1.addOne();
  instance1.printValue();
  wait(3, seconds);

  instance1.subtractOne();
  instance1.printValue();
  wait(3, seconds);

  // Class instance functions can accept parameters.
  instance1.resetValue(50);
  instance1.printValue();
}

