//----------------------------------------------------------------------------
//                                                                            
//    Project:          Motor Movements                                         
//    Description:      This example will show the different commands           
//                      available to control a motor
//    Brain Supported:  1st generation                       
//    Configuration:    Clawbot IQ (Drivetrain 2-motor, Gyro)
//                      Gyro in Port 4
//                      Arm Motor in Port 10  
//                      Claw Motor in Port 11     
//                                     
//---------------------------------------------------------------------------- 

// Include the IQ Library
#include "vex.h"

// Allows for easier use of the VEX Library
using namespace vex;

int main() {
  // Initializing Robot Configuration. DO NOT REMOVE!
  vexcodeInit();
  // Begin project code
  // Motors can spin forever until told to stop.
  ArmMotor.spin(forward);
  wait(1, seconds);
  ArmMotor.stop();

  // Motors can also spin for a distance based on the current position.
  ArmMotor.spinFor(90.0, degrees, true);

  // Motors can also spin to a specific rotation position.
  ArmMotor.spinToPosition(90.0, degrees, true);

  // Motor positions can be reset (set to zero) or set to any value.
  ArmMotor.setPosition(0.0, degrees);

  // Motors can change velocity (speed)
  ArmMotor.setVelocity(50.0, percent);

  // Motors can change their behavior when told to stop
  // brake - Motor will act like a brake to slow motion even faster.
  // coast - No power applied when stopping.
  // hold - Motor will hold its current position against external forces.
  ArmMotor.setStopping(brake);
  ArmMotor.setMaxTorque(50.0, percent);
  ArmMotor.setTimeout(1.0, seconds);
  ArmMotor.spinToPosition(360.0, degrees, true);
}

//----------------------------------------------------------------------------
//
//    Project:          Using the Timer                                      
//    Description:      This example will use the timer to control
//                      the duration of a while loop
//    Brain Supported:  1st generation
//    Configuration:    None
//
//---------------------------------------------------------------------------- 

// Include the IQ Library
#include "vex.h"

// Allows for easier use of the VEX Library
using namespace vex;

int main() {
  // Initializing Robot Configuration. DO NOT REMOVE!
  vexcodeInit();
  // Begin project code
  Brain.Timer.reset();

  // Use the timer value for the loop condition
  while (Brain.Timer.value() < 10) {
    // Clear the screen and reset the print cursor to the top left corner
    Brain.Screen.clearScreen();
    Brain.Screen.setCursor(1, 1);

    Brain.Screen.print("Timer: %.0f", Brain.Timer.value());

    // A brief delay to allow text to be printed without distortion or tearing
    wait(0.05, seconds);
  }

  Brain.Screen.clearScreen();
  Brain.Screen.setCursor(1, 1);
  Brain.Screen.print("10 seconds passed!");

}

