// ----------------------------------------------------------------------------
//                                                                            
//    Project:          Motor Sensing                                       
//    Description:      This example will show all of the available commands
//                      for using the Motor
//    Brain Supported:  1st generation              
//    Configuration:    Clawbot IQ (Drivetrain 2-motor, Gyro)
//                      Gyro in Port 4 
//                      Arm Motor in Port 10
//                      Claw Motor in Port 11               
//                                                                            
// ---------------------------------------------------------------------------- 

// Include the IQ Library
#include "vex.h"

// Allows for easier use of the VEX Library
using namespace vex;

int main() {
  // Initializing Robot Configuration. DO NOT REMOVE!
  vexcodeInit();
    ArmMotor.spin(forward);

  // A 'while loop' will cause the following set of commands to repeat 
  // until the Arm Motor is lifted.
  while (ArmMotor.position(degrees) < 800) {
    // Clear the screen and reset the print cursor to the top left corner.
    Brain.Screen.clearScreen();
    Brain.Screen.setCursor(1, 1);

    // The %.1f will print decimals with one 0 after the decimal.
    Brain.Screen.print("Velocity:%.1f rpm", ArmMotor.velocity(rpm));
    Brain.Screen.newLine();

    // The %.1f will print decimals with one 0 after the decimal.
    Brain.Screen.print("Current:%.1f amps", ArmMotor.current(amp));
    Brain.Screen.newLine();

    // The %.0f will print decimals with no 0's after the decimal.
    Brain.Screen.print("Position:%.0f degrees", ArmMotor.position(degrees));
    Brain.Screen.newLine();

    // A brief delay to allow text to be printed without distortion or tearing.
    wait(0.2, seconds);
  }
  // After the condition of the loop is met, the loop breaks, 
  // and the Arm Motor stops.
  ArmMotor.stop();
}

