    // The %.2f will print decimals with two 0's after the decimal.
    Brain.Screen.print("Position: %.2f degrees", ArmMotor.position(degrees));
    Brain.Screen.newLine();

    // The ArmMotor should spin down to the bumper and stop it.
    if (Bumper8.pressing()) {
        Brain.Screen.print("Bumper Pressed");
        ArmMotor.stop();
        break;
    }

    // A brief delay to allow text to be printed without distortion or tearing
    wait(0.2, seconds);
  }
}

