//----------------------------------------------------------------------------
//                                                                            
//    Project:          Left Arcade                                                                                                                                                  
//    Description:      The Left up/down Controller Axis (A) will drive the robot
//                      forward and backwards.
//                      The Left left/right Controller Axis (B) will turn the robot
//                      left and right.
//                      The deadband variable prevents drift when the Controller's
//                      joystick is released.
//    Brain Supported:  1st generation
//    Configuration:    Left Motor in Port 1
//                      Right Motor in Port 6
//                      Controller                                    
//                                                                            
//----------------------------------------------------------------------------

// Include the IQ Library
#include "vex.h"

// Allows for easier use of the VEX Library
using namespace vex;

int main() {
  // Initializing Robot Configuration. DO NOT REMOVE!
  vexcodeInit();
  // Begin project code

  // Set the deadband variable
  float deadband = 5.0;

  // Main controller loop to set motor velocities to controller axis positions
  while (true) {
    if (fabs(static_cast<float>(Controller.AxisA.position())) + fabs(static_cast<float>(Controller.AxisB.position())) > deadband) {
      LeftMotor.setVelocity((Controller.AxisA.position() + Controller.AxisB.position()), percent);
      RightMotor.setVelocity((Controller.AxisA.position() - Controller.AxisB.position()), percent);
    } else {
      LeftMotor.setVelocity(0, percent);
      RightMotor.setVelocity(0, percent);
    }
    LeftMotor.spin(forward);
    RightMotor.spin(forward);

    wait(20, msec);
  }
}

