// ------------------------------------------------------------------------------------------------------
//                                                                            
//    Project:          Comparing Values                                                                                                                                                 
//    Description:      This program looks at the variable to see if it is greater than or less than 10. 
//                      The message on the screen is updated according to that value.  If the value of 
//                      the variable is greater than 10, the program will print 'Value is more than 10' 
//                      on the screen.  If the value of the variable is less than 10, the program will 
//                      print, 'Value is less than 10' on the screen.
//    Brain Supported:  1st generation
//    Configuration:    None                                                  
//                                                                            
// ------------------------------------------------------------------------------------------------------

// Include the IQ Library
#include "vex.h"

// Allows for easier use of the VEX Library
using namespace vex;

int main() {
  // Initializing Robot Configuration. DO NOT REMOVE!
  vexcodeInit();
  int myVariable = 0;

  for (int i = 0; i < 20; i++) {
    // Display the current value of the variable
    Brain.Screen.print("myVariable: %d", myVariable);
    Brain.Screen.newLine();

    // Checks to see if the variable is equal to 10
    if (myVariable == 10) {
      Brain.Screen.print("Value equals 10");
    }

    // Checks to see if the variable is greater than 10
    if (myVariable > 10) {
      Brain.Screen.print("Value is more than 10");
    }

    // Checks to see if the variable is less than 10
    if (myVariable < 10) {
      Brain.Screen.print("Value is less than 10");
    }
    wait(1, seconds);

    // Clearing the screen and resetting the cursor
    Brain.Screen.clearScreen();
    Brain.Screen.setCursor(1, 1);

    // Adding one to the current variable value
    myVariable += 1;
  }
}

