//----------------------------------------------------------------------------
//                                                                            
//    Project:          Sense it Challenge                                                                                                                                                    
//    Description:      A reaction time game for the Testbed build. 
//                      Correctly trigger the sensors before time runs out. 
//                      Resets variables and sets Remaining time's calculation.
//    Brain Supported:  1st generation
//    Configuration:    Testbed
//                      Motors in Ports 1, 10, and 11
//                      Motor (Reversed) in Port 6
//                      TouchLEDs in Ports 2 and 9 
//                      Color Sensor in Port 3
//                      Gyro in Port 4
//                      Bumpers in Ports 5 and 8  
//                      Distance in Port 7                                      
//                                                                            
//----------------------------------------------------------------------------

// Include the IQ Library
#include "vex.h"

// Allows for easier use of the VEX Library
using namespace vex;

// A helper function to help pick random numbers
int mathRandomInt(int a, int b) {
  if (a > b) {
    // Swap a and b to ensure a is smaller.
    int c = a;
    a = b;
    b = c;
  }

  int tmpA = a;
  int tmpB = b;
  int r = tmpA + rand() / (RAND_MAX / (tmpB - tmpA + 1));
  return r;
}

int main() {
  // Initializing Robot Configuration. DO NOT REMOVE!
  vexcodeInit();
  // initialize the random number system
  srand(Brain.Timer.system());

  int score = 0;
  float maxTime = 120;
  int choice = 0;
  int fail = 0;
  int tempGoal = 0;
  float Remaining = maxTime - Brain.Timer.value();
  Brain.Timer.reset();
  TouchLEDPort2.setColor(colorType::none);
  TouchLEDPort9.setColor(colorType::none);

  // Displays Score and Time Remaining on screen
  // Sets game to repeat choosing random sensors/motors until the player fails
  while (!(fail > 0)) {
    Brain.Screen.setCursor(3, 1);
    Brain.Screen.print("Score = %d", score);
    Brain.Screen.setCursor(5, 1);
    Brain.Screen.clearLine(5);
    Brain.Screen.print("Time remaining = %.0f", Remaining);

    // We randomly select a dsensor that needs triggered
    choice = mathRandomInt(0, 9);

    // Bumper Switch Port 5
    // Gives player 1 point if they correctly pressed the Bumper in P5 within the time limit 
    // Gives player 1 (game-ending) fail if they do not 
    // Sets Remaining as maxTime - timer in seconds (current)
    if (choice == 0) {
      Brain.playSound(headlightsOn);
      wait(0.5, seconds);
      Brain.Screen.clearLine(1);
      Brain.Screen.setCursor(1, 1);
      Brain.Screen.print("Bumper Switch-Port 5");
      while ((!BumperPort5.pressing())) {
        if (Brain.Timer.value() > maxTime) {
          fail = 1;
          break;
        }
      wait(20, msec);
      }
      waitUntil((!BumperPort5.pressing()));
      if (fail == 0) {
        score += 1;
        Brain.playSound(tada);
        wait(0.5, seconds);
        Remaining = maxTime - Brain.Timer.value();
      }
    }

    // Bumper Switch in Port 8
    // Gives player 1 point if they correctly pressed the Bumper in P8 within the time limit
    // Gives player 1 (game-ending) fail if they do not
    // Sets Remaining as maxTime - timer in seconds (current)
    if (choice == 1) {
      Brain.playSound(headlightsOn);
      wait(0.5, seconds);
      Brain.Screen.clearLine(1);
      Brain.Screen.setCursor(1, 1);
      Brain.Screen.print("Bumper Switch-Port 8");
      while ((!BumperPort8.pressing())) {
        if (Brain.Timer.value() > maxTime) {
          fail = 1;
          break;
        }
      wait(20, msec);
      }
      waitUntil((!BumperPort8.pressing()));
      if (fail == 0) {
        score += 1;
        Brain.playSound(tada);
        Remaining = maxTime - Brain.Timer.value();
        wait(0.5, seconds);
      }
    }

    // Touch LED in Port 2
    // Gives player 1 point if they correctly presses the Touch LED in P2 within the time limit
    // Gives player 1 (game-ending) fail if they do not
    // Sets Remaining as maxTime - timer in seconds (current)
    if (choice == 2) {
      Brain.playSound(headlightsOn);
      wait(0.5, seconds);
      Brain.Screen.clearLine(1);
      Brain.Screen.setCursor(1, 1);
      Brain.Screen.print("Touch LED - Port 2");
      TouchLEDPort2.setColor(green);
      while ((!TouchLEDPort2.pressing())) {
        if (Brain.Timer.value() > maxTime) {
          fail = 1;
          break;
        }
      wait(20, msec);
      }
      TouchLEDPort2.setColor(colorType::none);
      waitUntil((!TouchLEDPort2.pressing()));
      if (fail == 0) {
        score += 1;
        Brain.playSound(tada);
        wait(0.5, seconds);
        Remaining = maxTime - Brain.Timer.value();
      }
    }

    // Touch LED in Port 9
    // Gives player 1 point if they correctly presses the Touch LED in P9 within the time limit
    // Gives player 1 (game-ending) fail if they do not
    // Sets Remaining as maxTime - timer in seconds (current)
    if (choice == 3) {
      Brain.playSound(headlightsOn);
      wait(0.5, seconds);
      Brain.Screen.clearLine(1);
      Brain.Screen.setCursor(1, 1);
      Brain.Screen.print("Touch LED - Port 9");
      TouchLEDPort9.setColor(green);
      while ((!TouchLEDPort9.pressing())) {
        if (Brain.Timer.value() > maxTime) {
          fail = 1;
          break;
        }
      wait(20, msec);
      }
      TouchLEDPort9.setColor(colorType::none);
      waitUntil((!TouchLEDPort9.pressing()));
      if (fail == 0) {
        score += 1;
        Brain.playSound(tada);
        Remaining = maxTime - Brain.Timer.value();
        wait(0.5, seconds);
      }
    }

    // Distance Sensor in Port 7
    // Gives player 1 point if they correctly hovers over the Distance Sensor in P7 within the time limit
    // Gives player 1 (game-ending) fail if they do not
    // Sets Remaining as maxTime - timer in seconds (current)
    if (choice == 4) {
      Brain.playSound(headlightsOn);
      wait(0.5, seconds);
      Brain.Screen.clearLine(1);
      Brain.Screen.setCursor(1, 1);
      Brain.Screen.print("Distance Sensor - Port 7");
      while ((Distance.distance(mm) > 50.0)) {
        if (Brain.Timer.value() > maxTime) {
          fail = 1;
          break;
        }
      wait(20, msec);
      }
      waitUntil((Distance.distance(mm) < 50.0));
      if (fail == 0) {
        score += 1;
        Brain.playSound(tada);
        wait(0.5, seconds);
        Remaining = maxTime - Brain.Timer.value();
      }
    }

    // Gyro Sensor in Port 4
    // Gives player 1 point if they correctly twists the Gyro in P4 within the time limit
    // Gives player 1 (game-ending) fail if they do not
    // Sets Remaining as maxTime - timer in seconds (current)
    if (choice == 5) {
      Brain.playSound(headlightsOn);
      wait(0.5, seconds);
      Brain.Screen.clearLine(1);
      Brain.Screen.setCursor(1, 1);
      Brain.Screen.print("Gyro Sensor - Port 4");
      tempGoal = Gyro.heading();
      while ((Brain.Timer.value() < maxTime || Brain.Timer.value() == maxTime)) {
        if (Gyro.heading() > tempGoal + 10.0) {
          break;
        }
        else {
          if (Gyro.heading() < tempGoal - 10.0 || Gyro.heading() == tempGoal - 10.0) {
            break;
          }
          else {
            if (Brain.Timer.value() > maxTime || Brain.Timer.value() == maxTime) {
              fail = 1;
              break;
            }
          }
        }
      wait(20, msec);
      }
      if (fail == 0) {
        score += 1;
        Brain.playSound(tada);
        Remaining = maxTime - Brain.Timer.value();
        wait(0.5, seconds);
      }
