// ----------------------------------------------------------------------------
//                                                                            
//    Project:          Menu Chooser                                       
//    Description:      This program allows the user to play sounds
//                      according to a button press on the VEX IQ 
//                      Robot Brain
//    Brain Supported:  1st generation
//    Configuration:    None            
//                                                                            
// ---------------------------------------------------------------------------- 

// Include the IQ Library
#include "vex.h"

// Allows for easier use of the VEX Library
using namespace vex;

// Initialize the variables we will be using
int selector;
int counter;

// Callback for when the Check button on the Brain is pressed
void checkButtonPressed() {
  // Play the sound according to the value of the selector variable
  if (selector == 1) {
    Brain.playSound(siren);
  }

  if (selector == 2) {
    Brain.playSound(wrongWay);
  }

  if (selector == 3) {
    Brain.playSound(fillup);
  }

  if (selector == 4) {
    Brain.playSound(headlightsOn);
  }

  if (selector == 5) {
    Brain.playSound(tollBooth);
  }
}

// Callback for when the Up button on the Brain is pressed
void upButtonPressed() {
  if (selector > 1) {
    selector -= 1;
  }
}

// Callback for when the Down button on the Brain is pressed
void downButtonPressed() {
  if (5 > selector) {
    selector += 1;
  }
}

int main() {
  // Initializing Robot Configuration. DO NOT REMOVE!
  vexcodeInit();
  // Setup the event handlers
  Brain.buttonCheck.pressed(checkButtonPressed);
  Brain.buttonUp.pressed(upButtonPressed);
  Brain.buttonDown.pressed(downButtonPressed);

  // Set the value of the variables to 1
  selector = 1;
  counter = 1;

  // Create a forever loop
  while (true) {
    Brain.Screen.clearLine(counter);
    if (selector == counter) {
      Brain.Screen.print("> ");
    }

    // Label the menu items here
    Brain.Screen.print("Sound: %d", counter);

    // Increase the value of the counter variable
    counter += 1;

    // If the variable is greater than 5, reset back to 1
    if (counter > 5) {
      counter = 1;
    }
    Brain.Screen.setCursor(counter, 1);
    wait(20, msec);
  }
}

