//    Description:      This program has the robot wait until the Touch 
//                      LED is pressed to drive forward
//    Brain Supported:  1st generation                  
//    Configuration:    Standard Drive Base (Drivetrain 2-motor, Gyro)
//                      Gyro in Port 4
//                      TouchLED in Port 2         
//                                                                            
// ---------------------------------------------------------------------------- 

// Include the IQ Library
#include "vex.h"

// Allows for easier use of the VEX Library
using namespace vex;

int main() {
  // Initializing Robot Configuration. DO NOT REMOVE!
  vexcodeInit();
    TouchLED2.setColor(red);
  // The robot will do nothing until the Touch LED is touched
  while (!TouchLED2.pressing()) {
    // A wait to allow other resources to run
    wait(0.2, seconds);
