//----------------------------------------------------------------------------
//                                                                            
//    Project:          Accurate Turns                                                                                                                                                
//    Description:      This example will turn the robot in different directions 
//                      to specific orientations and print that orientation
//    Brain Supported:  1st generation
//    Configuration:    LeftMotor in Port 1
//                      RightMotor in Port 6
//                      Gyro in Port 4                                   
//                                                                            
//----------------------------------------------------------------------------

// Include the IQ Library
#include "vex.h"

// Allows for easier use of the VEX Library
using namespace vex;

int main() {
  // Initializing Robot Configuration. DO NOT REMOVE!
  vexcodeInit();
  // Begin project code
  // Sets the Gyro orientation to zero, and sets the motor velocities to 20% 
  // for more accurate readings
  Gyro.calibrate(calNormal);
  Gyro.setHeading(0.0, degrees);
  LeftMotor.setVelocity(20.0, percent);
  RightMotor.setVelocity(20.0, percent);

  // Starts both left and right motors to turn to the left
  LeftMotor.spin(reverse);
  RightMotor.spin(forward);
  wait(0.25, seconds);

  // Waits until the Gyro's orientation is equal to or is greater than 50 to stop the motors
  waitUntil(Gyro.heading() > 50.0);
  LeftMotor.stop();
  RightMotor.stop();

  // Prints the reading of the Gyro to the robot brain's screen
  Brain.Screen.print("%.2f", Gyro.heading());
  Brain.Screen.setCursor(2, 1);
  wait(1.0, seconds);

  // Starts the left and right motors to turn to the right
  LeftMotor.spin(forward);
  RightMotor.spin(reverse);
  wait(0.25, seconds);

  // Ensures that the Gyro goes past the zero degree orientation
  waitUntil(Gyro.heading() > 60.0);

  // Waits till the Gyro's orientation is equal to or is greater than 180 to stop the motors.
  waitUntil(Gyro.heading() < 180.0);
  LeftMotor.stop();
  RightMotor.stop();

  // Prints the Gyro's orientation
  Brain.Screen.print("%.2f", Gyro.heading());

  return 0;
}

//------------------------------------------------------------------------------------
//                                                                            
//    Project:          Claw and Arm                                         
//    Description:      This example will show how to use Clawbot to grab an object 
//                      and transports it forward. The Clawbot then places the object 
//                      down and returns to its original spot.
//    Brain Supported:  1st generation
//    Configuration:    Clawbot IQ (Drivetrain 2-motor)
//                      Gyro in Port 4
//                      ArmMotot in Port 10
//                      ClawMotor in Port 11
//                                                                                          
//------------------------------------------------------------------------------------

// Include the IQ Library
#include "vex.h"

// Allows for easier use of the VEX Library
using namespace vex;

int main() {
  // Initializing Robot Configuration. DO NOT REMOVE!
  vexcodeInit();
    // Begin project code

  // Set the Arm stopping to hold mode
  ArmMotor.setStopping(hold);

  // Set the encoder values of both the Arm and Claw motor encoders to zero
  ClawMotor.setPosition(0.0, degrees);
  ArmMotor.setPosition(0.0, degrees);

  // Set motion timeout to prevent damage to the arm/claw if the object is too large
  ClawMotor.setTimeout(1.0, seconds);
  ArmMotor.setTimeout(1.0, seconds);

  // Close the Claw on an object
  ClawMotor.spinFor(forward, 60.0, degrees, true);
  wait(1.0, seconds);

  // Raise the Arm
  ArmMotor.spinFor(forward, 2.0, turns, true);

  // Drive Forward
  Drivetrain.driveFor(forward, 10.0, inches, true);

  // Lower the Arm
  ArmMotor.spinFor(reverse, 2.0, turns, true);

  // Open the Claw
  ClawMotor.spinFor(reverse, 45.0, degrees, true);

  // Move the robot back to the original starting place
  wait(1.0, seconds);
  Drivetrain.driveFor(reverse, 10.0, inches, true);

  return 0;
}

//------------------------------------------------------------------------------------
//                                                                            
//    Project:          Clawbot Controller with Events
//                                                                                                                                                
//    Description:      The Left up/down Controller Axis (A) will control the
//                      speed of the left motor.
//                      The Right up/down Controller Axis (D) will control the
//                      speed of the right motor.
//                      The Left up/down Controller Buttons will control the Arm.
//                      The Right up/down Controller Buttons will control the Claw.
//    Brain Supported:  1st generation
//    Configuration:    Controller
//                      Left Motor in Port 1
//                      Right Motor in Port 6
//                      Claw Motor in Port 11
//                      Arm Motor in Port 10                            
//                                                                            
//------------------------------------------------------------------------------------

// Include the IQ Library
#include "vex.h"

// Allows for easier use of the VEX Library
using namespace vex;

// Callback function when Controller ButtonLUp is pressed
void onButtonLUpPress() {
  // Spinning the ArmMotor in forward raises the Arm
  ArmMotor.spin(forward);

  while (Controller.ButtonLUp.pressing()) {
    // Wait until ButtonLUp is released
    wait(20, msec);
  }

  ArmMotor.stop();
}

// Callback function when Controller ButtonLDown is pressed
void onButtonLDownPress() {
  // Spinning the ArmMotor in reverse lowers the Arm
  ArmMotor.spin(reverse);

  while (Controller.ButtonLDown.pressing()) {
    // Wait until ButtonLDown is released
    wait(20, msec);
  }

  ArmMotor.stop();
}

// Callback function when Controller ButtonRUp is pressed
void onButtonRUpPress() {
  // Spinning the ClawMotor forward closes the Claw
  ClawMotor.spin(forward);

  while (Controller.ButtonRUp.pressing()) {
    // Wait until ButtonRUp is released
    wait(20, msec);
  }

  ClawMotor.stop();
}

// Callback function when Controller ButtonRDown is pressed
void onButtonRDownPress() {
  // Spinning the ClawMotor in reverse opens the Claw
  ClawMotor.spin(reverse);

  while (Controller.ButtonRDown.pressing()) {
    // Wait until ButtonRDown is released
    wait(20, msec);
  }

  ClawMotor.stop();
}

int main() {
  // Initializing Robot Configuration. DO NOT REMOVE!
  vexcodeInit();
  // Begin project code

  // Register event handlers and pass callback functions
  Controller.ButtonLUp.pressed(onButtonLUpPress);
  Controller.ButtonLDown.pressed(onButtonLDownPress);
  Controller.ButtonRUp.pressed(onButtonRUpPress);
  Controller.ButtonRDown.pressed(onButtonRDownPress);

  // Set default motor stopping behavior and velocity
  ArmMotor.setStopping(hold);
  ClawMotor.setStopping(hold);
  ArmMotor.setVelocity(60, percent);
  ClawMotor.setVelocity(30, percent);

  // Loop to check Controller Axis positions and set motor velocity
  while (true) {
    LeftMotor.setVelocity(Controller.AxisA.position(), percent);
    RightMotor.setVelocity(Controller.AxisD.position(), percent);

    LeftMotor.spin(forward);
    RightMotor.spin(forward);

    wait(20, msec);
  }
}

