// --------------------------------------------------------------------
//
//    Project:          Detecting Colors
//    Description:      This example will continuously detect colors and 
//                      will have the robot react different ways
//                      depending on which color is detected
//    Brain Supported:  1st generation
//    Configuration:    Drivetrain 2-motor
//                      Gyro in Port 4
//                      Color in Port 3
//
// --------------------------------------------------------------------

// Include the IQ Library
#include "vex.h"

// Allows for easier use of the VEX Library
using namespace vex;

int main() {
  // Initializing Robot Configuration. DO NOT REMOVE!
  vexcodeInit();
    // Begin project code
  while (true) {

    // If the Color Sensor detects red, the robot will drive forward three inches
    if (Color3.detects(red)) {
      Drivetrain.driveFor(forward, 3.0, inches, true);
    } else if (Color3.detects(blue)) {
      // If the Color Sensor detects blue, the robot will drive backward three inches
      Drivetrain.driveFor(reverse, 3.0, inches, true);
    } else if (Color3.detects(green)) {
      // If the Color Sensor detects green, the robot will turn 90 degrees to the right
      Drivetrain.turnFor(right, 90.0, degrees, true);
    } else if (Color3.detects(yellow)) {
      // If the Color Sensor detects yellow, the robot will turn 90 degrees to the left
      Drivetrain.turnFor(left, 90.0, degrees, true);
      // If none of the above colors are detected, the robot will do nothing
    } else {
      // Print if no color is detected
      Brain.Screen.print("No Color Detected");
      wait(0.5, seconds);
      // Clears the screen if no color is detected
      Brain.Screen.clearScreen();
      Brain.Screen.setCursor(1, 1);
    }
    wait(20, msec);
  }

  return 0;
}

