int main() {
  // Initializing Robot Configuration. DO NOT REMOVE!
  vexcodeInit();
  // Begin project code
  // Take the current postion of the Arm as zero
  ArmMotor.setPosition(0.0, degrees);

  // Move the Arm up and hold the position for 2 seconds
  ArmMotor.spinFor(forward, 90.0, degrees, true);
  wait(2.0, seconds);

  // Lower the Arm and hold that position for 2 seconds
  ArmMotor.spinFor(reverse, 20.0, degrees, true);
