//    Project:          Use the Claw                                      
//    Description:      This example will show how to open the claw to 
//                      a specific position and hold that position. 
//                      Next, slightly close the Claw to another position and hold 
//                      that position. Finally, close the Claw to the original position.
//    Brain Supported:  1st generation       
//    Configuration:    ClawMotor in Port 11               
//                                                                            
//--------------------------------------------------------------------------------------

// Include the IQ Library
#include "vex.h"

