using namespace vex;

int main() {
  // Initializing Robot Configuration. DO NOT REMOVE!
  vexcodeInit();
  // Begin project code
  // Take the current position of the Claw as zero
  ClawMotor.setPosition(0.0, degrees);

  // Set the Claw's timeout
  ClawMotor.setTimeout(2.0, seconds);

  // Open up the Claw and hold the position for two seconds
  ClawMotor.spinFor(reverse, 60.0, degrees, true);
  wait(2.0, seconds);

  // Close the Claw slightly and hold that position for two seconds
  ClawMotor.spinFor(forward, 25.0, degrees, true);
  wait(2.0, seconds);

  // Return the Claw to its original position
  ClawMotor.spinToPosition(0.0, degrees, true);

  return 0;
}

