//    Project:          Distance Sensing (2nd gen sensor)                                      
//    Description:      This example will show all of the available commands
//                      using the Distance Sensor (2nd gen sensor)
//    Brain Supported:  1st generation                 
//    Configuration:    Distance (2nd gen sensor) in Port 7              
//                                                                            
// ---------------------------------------------------------------------------- 

// Include the IQ Library
#include "vex.h"

// Allows for easier use of the VEX Library
using namespace vex;

int main() {
  // Initializing Robot Configuration. DO NOT REMOVE!
  vexcodeInit();
  // Begin project code

  // Loop to print all distance sensing values to the screen
  while (true) {
    // Clear the screen and set cursor to top left corner of the screen
    Brain.Screen.clearScreen();
    Brain.Screen.setCursor(1, 1);

    // The %s will be replaced by the string passed as the second argument
    Brain.Screen.print("Found Object: %s", Distance7.isObjectDetected() ? "TRUE" : "FALSE");
    Brain.Screen.newLine();

    Brain.Screen.print("Distance - mm: %0.1f", Distance7.objectDistance(mm));
    Brain.Screen.newLine();

    Brain.Screen.print("Distance - in: %0.1f", Distance7.objectDistance(inches));
    Brain.Screen.newLine();

    Brain.Screen.print("Velocity - m/s: %0.1f", Distance7.objectVelocity());
    Brain.Screen.newLine();

    // Use an if/else if/else statement to print the size of the object detected by the distance sensor
    Brain.Screen.print("Object Size: ");
    if (Distance7.objectSize() == sizeType::small) {
      Brain.Screen.print("small");
      Brain.Screen.newLine();
    } else if (Distance7.objectSize() == sizeType::medium) {
      Brain.Screen.print("medium");
      Brain.Screen.newLine();
    } else {
      Brain.Screen.print("large");
      Brain.Screen.newLine();
    }

    // A brief delay to allow text to be printed without distortion or tearing
    wait(0.2, seconds);
  }
  return 0;
}

