//------------------------------------------------------------------------------------
//                                                                            
//    Project:          Using Optical Sensor                                         
//    Description:      This example will print out the name, hue, and brightness 
//                      of the color that the Optical Sensor detects to the Brain screen
//    Brain Supported:  1st generation
//    Configuration:    Optical Sensor in Port 3            
//                                                                            
//------------------------------------------------------------------------------------ 

// Include the IQ Library
#include "vex.h"

// Allows for easier use of the VEX Library
using namespace vex;

int main() {
  // Initializing Robot Configuration. DO NOT REMOVE!
  vexcodeInit();
  // Begin project code

  // Turn the Optical Sensor Lamp on
  Optical3.setLight(ledState::on);

  while (true) {
    // Erase the Brain screen at the beginning of the project and set
    // the printing location (cursor) to the top left corner
    Brain.Screen.clearScreen();
    Brain.Screen.setCursor(1, 1);

    // We want to only get information from the sensor if the object is found
    if (Optical3.isNearObject()) {
      Brain.Screen.print("Object found");
      Brain.Screen.newLine();

      // Use an if/else if/else statement to print the color detected by the Optical Sensor
      if (Optical3.colorname() == red) {
        Brain.Screen.print("Detects: red");
        Brain.Screen.newLine();
      } else if (Optical3.colorname() == green) {
        Brain.Screen.print("Detects: green");
        Brain.Screen.newLine();
      } else if (Optical3.colorname() == blue) {
        Brain.Screen.print("Detects: blue");
        Brain.Screen.newLine();
      } else if (Optical3.colorname() == yellow) {
        Brain.Screen.print("Detects: yellow");
        Brain.Screen.newLine();
      } else if (Optical3.colorname() == orange) {
        Brain.Screen.print("Detects: orange");
        Brain.Screen.newLine();
      } else if (Optical3.colorname() == purple) {
        Brain.Screen.print("Detects: purple");
        Brain.Screen.newLine();
      } else if (Optical3.colorname() == cyan) {
        Brain.Screen.print("Detects: cyan");
        Brain.Screen.newLine();
      } else {
        Brain.Screen.print("Unknown color");
        Brain.Screen.newLine();
      }

      Brain.Screen.print("Brightness: %0.1f", Optical3.brightness());
      Brain.Screen.newLine();

      Brain.Screen.print("Hue: %0.1f", Optical3.hue());
      Brain.Screen.newLine();
    }
    else {
      // If an object is not found, we may be getting incorrect values
      Brain.Screen.print("No object found");
    }
    // A brief delay to allow text to be printed without distortion or tearing
    wait(0.2, seconds);
  }
  return 0;
}

