// Include the IQ Library
#include "vex.h"

// Allows for easier use of the VEX Library
using namespace vex;

int main() {
  // Initializing Robot Configuration. DO NOT REMOVE!
  vexcodeInit();
  // Begin project code
  TouchLED2.setBrightness(100);

  // Use a while loop to keep checking
  // the Inertial Sensor's acceleration along the X, Y, and Z-axes
  while (true) {
    if (BrainInertial.acceleration(xaxis) < -0.5) {
      // Tilt the front of the BaseBot downwards - the TouchLED will be set to red
      TouchLED2.setColor(red);
    } else if (BrainInertial.acceleration(yaxis) < -0.5) {
      // Tilt the BaseBot on the right side - the TouchLED will be set to green
      TouchLED2.setColor(green);
    } else if (BrainInertial.acceleration(zaxis) < -0.5) {
      // Tilt the BaseBot back to the original position - the TouchLED will be set to blue
      TouchLED2.setColor(blue);
    } else {
      // Tilt the front of the BaseBot backwards - the TouchLED will turn off
      TouchLED2.setColor(colorType::none);
    }
  }
}

