// Include the IQ Library
#include "vex.h"

// Allows for easier use of the VEX Library
using namespace vex;

int main() {
  // Initializing Robot Configuration. DO NOT REMOVE!
  vexcodeInit();
  // Begin project code
  // Change the font size to fit on the IQ (2nd generation) Brain's screen
  Brain.Screen.setFont(mono12);

  while (true) {

    // If the Optical Sensor detects red, the robot will drive forward three inches
    if (Optical3.color() == red) {
      Drivetrain.driveFor(forward, 3.0, inches, true);
    } else if (Optical3.color() == blue) {
      // If the Optical Sensor detects blue, the robot will drive backward three inches
      Drivetrain.driveFor(reverse, 3.0, inches, true);
    } else if (Optical3.color() == green) {
      // If the Optical Sensor detects green, the robot will turn 90 degrees to the right
      Drivetrain.turnFor(right, 90.0, degrees, true);
    } else if (Optical3.color() == yellow) {
      // If the Optical Sensor detects yellow, the robot will turn 90 degrees to the left
      Drivetrain.turnFor(left, 90.0, degrees, true);
      // If none of the above colors are detected, the robot will do nothing
    } else {
      // Print if no color is detected
      Brain.Screen.print("No Color Detected");
      wait(0.5, seconds);
      // Clears the screen if no color is detected
      Brain.Screen.clearScreen();
      Brain.Screen.setCursor(1, 1);
    }
    wait(20, msec);
  }

  return 0;
}

