//    Description:      The Left up/down Controller Axis (A) will control the
//                      speed of the left motor.
//                      The Right up/down Controller Axis (D) will control the
//                      speed of the right motor.
//                      The Left up/down Controller Buttons will control the Arm.
//                      The Right up/down Controller Buttons will control the Claw.
//    Brain Supported:  2nd generation
//    Configuration:    Left Motor in Port 1
//                      Right Motor in Port 6
//                      Claw Motor in Port 4
//                      Arm Motor in Port 10
//                      Controller                          
//                                                                            
//----------------------------------------------------------------------------

// Include the IQ Library
#include "vex.h"

// Allows for easier use of the VEX Library
using namespace vex;

// Callback function when Controller ButtonLUp is pressed
void onButtonLUpPress() {
  // Spinning the ArmMotor in forward raises the Arm
  ArmMotor.spin(forward);

  while (Controller.ButtonLUp.pressing()) {
    // Wait until ButtonLUp is released
    wait(20, msec);
  }

  ArmMotor.stop();
}

// Callback function when Controller ButtonLDown is pressed
void onButtonLDownPress() {
  // Spinning the ArmMotor in reverse lowers the Arm
  ArmMotor.spin(reverse);

  while (Controller.ButtonLDown.pressing()) {
    // Wait until ButtonLDown is released
    wait(20, msec);
  }

  ArmMotor.stop();
}

// Callback function when Controller ButtonRUp is pressed
void onButtonRUpPress() {
  // Spinning the ClawMotor forward closes the Claw
  ClawMotor.spin(forward);

  while (Controller.ButtonRUp.pressing()) {
    // Wait until ButtonRUp is released
    wait(20, msec);
  }

  ClawMotor.stop();
}

// Callback function when Controller ButtonRDown is pressed
void onButtonRDownPress() {
  // Spinning the ClawMotor in reverse opens the Claw
  ClawMotor.spin(reverse);

  while (Controller.ButtonRDown.pressing()) {
    // Wait until ButtonRDown is released
    wait(20, msec);
  }

  ClawMotor.stop();
}

int main() {
  // Initializing Robot Configuration. DO NOT REMOVE!
  vexcodeInit();
  // Begin project code

  // Register event handlers and pass callback functions
  Controller.ButtonLUp.pressed(onButtonLUpPress);
  Controller.ButtonLDown.pressed(onButtonLDownPress);
  Controller.ButtonRUp.pressed(onButtonRUpPress);
  Controller.ButtonRDown.pressed(onButtonRDownPress);

  // Set default motor stopping behavior and velocity
  ArmMotor.setStopping(hold);
  ClawMotor.setStopping(hold);
  ArmMotor.setVelocity(60, percent);
  ClawMotor.setVelocity(30, percent);

  // Loop to check Controller Axis positions and set motor velocity
  while (true) {
    LeftMotor.setVelocity(Controller.AxisA.position(), percent);
    RightMotor.setVelocity(Controller.AxisD.position(), percent);

    LeftMotor.spin(forward);
    RightMotor.spin(forward);

    wait(20, msec);
  }
}

