  // Set the encoder values of both the Arm and Claw motor encoders to zero
  ClawMotor.setPosition(0.0, degrees);
  ArmMotor.setPosition(0.0, degrees);

  // Set motion timeout to prevent damage to the arm/claw if the object is too large
