    float inertialRoll = BrainInertial.orientation(roll, degrees);
    float inertialYaw = BrainInertial.orientation(yaw, degrees);

    if (inertialPitch > 10.0 || inertialPitch < -10.0) {
      // Rotate the BaseBot forward and backward along the Y-axis for pitch
      // TouchLED will turn green when +/- 10 degrees from calibration position along the Y-axis
      TouchLED2.setColor(green);
      Brain.Screen.setCursor(1, 1);
      Brain.Screen.print("Pitch: %.1f", inertialPitch);
      Brain.Screen.newLine();
      Brain.Screen.print("Rotation: Y axis");
      wait(0.1, seconds);
      Brain.Screen.clearScreen();
    } else if (inertialRoll > 10.0 || inertialRoll < -10.0) {
      // Rotate the BaseBot on it's left and right side along the X-axis for roll
      // TouchLED will turn red when +/- 10 degrees from calibration position along the X-axis
      TouchLED2.setColor(red);
      Brain.Screen.setCursor(1, 1);
      Brain.Screen.print("Roll: %.1f", inertialRoll);
      Brain.Screen.newLine();
      Brain.Screen.print("Rotation: X axis");
      wait(0.1, seconds);
      Brain.Screen.clearScreen();
    } else if (inertialYaw > 10.0 || inertialYaw < -10.0) {
      // Turn the BaseBot left and right along the Z-axis for yaw
      // TouchLED will turn blue when +/- 10 degrees from calibration position along the Z-axis
      TouchLED2.setColor(blue);
      Brain.Screen.setCursor(1, 1);
      Brain.Screen.print("Yaw: %.1f", inertialYaw);
      Brain.Screen.newLine();
      Brain.Screen.print("Rotation: Z axis");
      wait(0.1, seconds);
      Brain.Screen.clearScreen();
    } else {
      // Rotate the BaseBot back to it's original calibration position
      TouchLED2.setColor(colorType::none);
      Brain.Screen.setCursor(1, 1);
      Brain.Screen.print("None");
      Brain.Screen.newLine();
      wait(0.25, seconds);
      Brain.Screen.clearLine(1);
    }
  }
