    Pneumatic5.retract(cylinder2);
    // Turn off the air pump after a short delay since we are not moving the cylinders
    wait(1.0, seconds);
    Pneumatic5.pumpOff();
    // Wait 10 seconds before repeating the cycle
    wait(10.0, seconds);
  }
}

